// ─── Config helpers (mirrors lib/stellarConfig.ts) ──────────────────────────

function getNetworkConfig(): { network: string; horizonUrl: string } {
  if (typeof window === "undefined") {
    const network = (process.env.NEXT_PUBLIC_STELLAR_NETWORK || "testnet") as
      | "testnet"
      | "mainnet";
    return network === "mainnet"
      ? { network: "mainnet", horizonUrl: "https://horizon.stellar.org" }
      : { network: "testnet", horizonUrl: "https://horizon-testnet.stellar.org" };
  }
  const stored = localStorage.getItem("finchippay:network");
  if (stored) {
    try {
      return JSON.parse(stored);
    } catch {
      // ignore
    }
  }
  return { network: "testnet", horizonUrl: "https://horizon-testnet.stellar.org" };
}

function getNetworkPassphrase(): string {
  const cfg = getNetworkConfig();
  return cfg.network === "mainnet" ? Networks.PUBLIC : Networks.TESTNET;
}

function getSorobanRpcUrl(): string {
  const cfg = getNetworkConfig();
  if (cfg.network === "mainnet") return "https://soroban.stellar.org";
  return "https://soroban-testnet.stellar.org";
}

let _server: Horizon.Server | null = null;
function getServer(): Horizon.Server {
  const cfg = getNetworkConfig();
  if (!_server || _server.serverURL.toString() !== cfg.horizonUrl) {
    _server = new Horizon.Server(cfg.horizonUrl);
  }
  return _server;
}

let _sorobanServer: rpc.Server | null = null;
function getSorobanServer(): rpc.Server {
  const url = getSorobanRpcUrl();
  if (!_sorobanServer || _sorobanServer.serverURL.toString() !== url) {
    _sorobanServer = new rpc.Server(url);
  }
  return _sorobanServer;
}

