async function simulateView(
  contractId: string,
  method: string,
  args: xdr.ScVal[],
  source = "GAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAWHF",
): Promise<rpc.Api.SimulateTransactionSuccessResponse | null> {
  const contract = new Contract(contractId);
  const tx = new TransactionBuilder(new Account(source, "0"), {
    fee: String(BASE_FEE_STROOPS),
    networkPassphrase: getNetworkPassphrase(),
  })
    .addOperation(contract.call(method, ...args))
    .setTimeout(30)
    .build();

  const sim = await getSorobanServer().simulateTransaction(tx);
  if (rpc.Api.isSimulationSuccess(sim) && sim.result) {
    return sim;
  }
  return null;
}

// ─── Simulate a write (build + preflight) ──────────────────────────────────

async function buildAndPrepare(
  contractId: string,
  sourcePublicKey: string,
  method: string,
  args: xdr.ScVal[],
  timeout = TX_TIMEOUT_SECONDS,
): Promise<Transaction> {
  const sourceAccount = await getServer().loadAccount(sourcePublicKey);
  const contract = new Contract(contractId);

  const tx = new TransactionBuilder(sourceAccount, {
    fee: String(BASE_FEE_STROOPS),
    networkPassphrase: getNetworkPassphrase(),
  })
    .addOperation(contract.call(method, ...args))
    .setTimeout(timeout)
    .build();

  const simulated = await getSorobanServer().simulateTransaction(tx);
  if (rpc.Api.isSimulationError(simulated)) {
    throw new Error(`Simulation failed for ${method}: ${simulated.error}`);
  }

  return getSorobanServer().prepareTransaction(tx);
}

